def compute_a_n(n):
    if n == 1:
        return 1
    elif n == 2:
        return 2
    else:
        a_prev_prev = 1  # a_1
        a_prev = 2       # a_2
        for i in range(3, n+1):
            a_current = 3 * a_prev - 2 * a_prev_prev
            a_prev_prev, a_prev = a_prev, a_current
        return a_prev

